prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?norm ?orig WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?norm . }
  OPTIONAL { ?model tai:originalId ?orig . }
  FILTER(
    CONTAINS(LCASE(STR(?norm)), LCASE("0ba102e82f484407a4dbcb9bcafdd920"))
    || CONTAINS(LCASE(STR(?orig)), LCASE("0ba102e82f484407a4dbcb9bcafdd920"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
}
ORDER BY LCASE(STR(?taskName))
LIMIT 25
